   154	
   155	type bucketCount struct {
   156		le    string
   157		count uint64
   158	}
   159	
   160	func histogramSnapshot(t *testing.T, h *Histogram) ([]bucketCount, float64, uint64) {
   161		t.Helper()
   162	
   163		var out strings.Builder
   164		h.Write(&out)
   165	
   166		var buckets []bucketCount
   167		var sum float64
   168		var count uint64
   169		var foundSum, foundCount bool
   170	
   171		for _, line := range strings.Split(strings.TrimSpace(out.String()), "\n") {
   172			fields := strings.Fields(line)
   173			if len(fields) != 2 {
   174				continue
   175			}
   176	
   177			switch fields[0] {
   178			case "test_histogram_sum":
   179				var err error
   180				sum, err = strconv.ParseFloat(fields[1], 64)
   181				if err != nil {
   182					t.Fatalf("parse sum %q: %v", fields[1], err)
   183				}
   184				foundSum = true
   185			case "test_histogram_count":
   186				var err error
   187				count, err = strconv.ParseUint(fields[1], 10, 64)
   188				if err != nil {
   189					t.Fatalf("parse count %q: %v", fields[1], err)
   190				}
   191				foundCount = true
   192			default:
   193				const bucketPrefix = `test_histogram_bucket{le="`
   194				const bucketSuffix = `"}`
   195				if strings.HasPrefix(fields[0], bucketPrefix) && strings.HasSuffix(fields[0], bucketSuffix) {
   196					bucketValue, err := strconv.ParseUint(fields[1], 10, 64)
   197					if err != nil {
   198						t.Fatalf("parse bucket count %q: %v", fields[1], err)
   199					}
   200					le := strings.TrimSuffix(strings.TrimPrefix(fields[0], bucketPrefix), bucketSuffix)
   201					buckets = append(buckets, bucketCount{le: le, count: bucketValue})
   202				}
   203			}
   204		}
   205	
   206		if !foundSum {
   207			t.Fatalf("histogram sum not found in output:\n%s", out.String())
   208		}
   209		if !foundCount {
   210			t.Fatalf("histogram count not found in output:\n%s", out.String())
   211		}
   212	
   213		return buckets, sum, count
   214	}
